//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageredshiftimport("github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/redshift""github.com/hashicorp/terraform-provider-aws/internal/flex")funcflattenLogging(ls*redshift.LoggingStatus)[]interface{}{ifls==nil{return[]interface{}{}}cfg:=make(map[string]interface{})cfg["enable"]=aws.BoolValue(ls.LoggingEnabled)ifls.BucketName!=nil{cfg["bucket_name"]=aws.StringValue(ls.BucketName)}ifls.LogDestinationType!=nil{cfg["log_destination_type"]=aws.StringValue(ls.LogDestinationType)}ifls.LogExports!=nil{cfg["log_exports"]=flex.FlattenStringSet(ls.LogExports)}ifls.S3KeyPrefix!=nil{cfg["s3_key_prefix"]=aws.StringValue(ls.S3KeyPrefix)}return[]interface{}{cfg}}funcflattenSnapshotCopy(scs*redshift.ClusterSnapshotCopyStatus)[]interface{}{ifscs==nil{return[]interface{}{}}cfg:=make(map[string]interface{})ifscs.DestinationRegion!=nil{cfg["destination_region"]=aws.StringValue(scs.DestinationRegion)}ifscs.RetentionPeriod!=nil{cfg["retention_period"]=aws.Int64Value(scs.RetentionPeriod)}ifscs.SnapshotCopyGrantName!=nil{cfg["grant_name"]=aws.StringValue(scs.SnapshotCopyGrantName)}return[]interface{}{cfg}}